pageContent:
.gestion-container {
  padding: 1rem;
}

.header {
  margin-bottom: 2rem;
}

.header h2 {
  color: #d4af37;
  text-transform: uppercase;
  margin-bottom: 0.2rem;
}

.header p {
  color: #888;
  font-size: 0.9rem;
}

.table-wrapper {
  overflow-x: auto;
  background: rgba(20, 20, 20, 0.5);
  border-radius: 10px;
  border: 1px solid rgba(255,255,255,0.1);
}

.admin-table {
  width: 100%;
  border-collapse: collapse;
  color: #eee;
}

.admin-table th, .admin-table td {
  padding: 1rem;
  text-align: left;
  border-bottom: 1px solid rgba(255,255,255,0.05);
}

.admin-table th {
  background: rgba(212, 175, 55, 0.1);
  color: #d4af37;
  font-weight: bold;
  text-transform: uppercase;
  font-size: 0.85rem;
}

.admin-table tr:hover {
  background: rgba(255,255,255,0.02);
}

.price {
  font-weight: bold;
  color: #d4af37;
}

.articulos-cell {
  display: flex;
  flex-direction: column;
  gap: 0.2rem;
  font-size: 0.85rem;
  color: #ccc;
}

/* Status Dropdown */
.status-select {
  padding: 0.4rem 0.8rem;
  border-radius: 5px;
  background: #111;
  color: #fff;
  border: 1px solid rgba(255,255,255,0.2);
  cursor: pointer;
  outline: none;
  font-weight: 500;
  transition: all 0.3s;
}

.status-select:focus {
  border-color: #d4af37;
}

.status-select.pendiente { border-color: #d4af37; color: #d4af37; }
.status-select.preparando { border-color: #3498db; color: #3498db; }
.status-select.enviado { border-color: #e67e22; color: #e67e22; }
.status-select.entregado { border-color: #2ecc71; color: #2ecc71; }
.status-select.cancelado { border-color: #e74c3c; color: #e74c3c; }

.loading {
  display: flex;
  justify-content: center;
  padding: 3rem;
}

.spinner {
  width: 40px;
  height: 40px;
  border: 4px solid rgba(212, 175, 55, 0.1);
  border-top: 4px solid #d4af37;
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  0% { transform: rotate(0deg); }
  100% { transform: rotate(360deg); }
}

/* Toast Styles */
.toast-notification {
  position: fixed;
  bottom: 30px;
  right: 30px;
  background: #282828;
  color: #d4af37;
  padding: 1rem 2rem;
  border-radius: 10px;
  border: 1px solid #d4af37;
  box-shadow: 0 5px 20px rgba(0,0,0,0.5);
  transform: translateY(100px);
  opacity: 0;
  transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  z-index: 1000;
  font-weight: bold;
}

.toast-notification.show {
  transform: translateY(0);
  opacity: 1;
}
